DROP TABLE IF EXISTS `purchase_requisition`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `purchase_requisition` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `farm_id` int unsigned NOT NULL,
  `product_id` int unsigned NOT NULL,
  `quantity` int unsigned NOT NULL,
  `max_price_per_unit` decimal(12,2) DEFAULT NULL,
  `offer_date` date DEFAULT NULL,
  `required_date` date DEFAULT NULL,
  `priority` int unsigned DEFAULT NULL,
  `valid_until` date DEFAULT NULL,
  `status` enum('draft','delivering','approved','completed','cancelled') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'draft',
  `notes` text COLLATE utf8mb4_general_ci,
  PRIMARY KEY (`id`),
  KEY `fk_requisition_farm` (`farm_id`),
  KEY `fk_requisition_product` (`product_id`),
  CONSTRAINT `fk_requisition_farm` FOREIGN KEY (`farm_id`) REFERENCES `farm` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_requisition_product` FOREIGN KEY (`product_id`) REFERENCES `product` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=451 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
